package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.Reader;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.MockedConstruction;
import org.mockito.Mockito;

class CSVParserTest {

    private CSVFormat formatMock;
    private Reader readerMock;

    @BeforeEach
    void setUp() {
        formatMock = mock(CSVFormat.class);
        readerMock = mock(Reader.class);
    }

    @Test
    void testParse_WithValidReaderAndFormat_ReturnsCSVParserInstance() throws IOException {
        try (MockedConstruction<CSVParser> mocked = Mockito.mockConstruction(CSVParser.class,
                (mock, context) -> {
                    when(mock.getHeaderMap()).thenReturn(null);
                    when(mock.isClosed()).thenReturn(false);
                })) {

            CSVParser parser = CSVParser.parse(readerMock, formatMock);

            assertNotNull(parser);
            // Verify constructor was called with correct arguments
            assertEquals(1, mocked.constructed().size());
            CSVParser constructedParser = mocked.constructed().get(0);
            assertSame(constructedParser, parser);
        }
    }

    @Test
    void testParse_ThrowsIOExceptionWhenConstructorThrows() throws IOException {
        try (MockedConstruction<CSVParser> mocked = Mockito.mockConstruction(CSVParser.class,
                (mock, context) -> {
                    throw new IOException("Test IOException");
                })) {
            IOException exception = assertThrows(IOException.class, () -> {
                CSVParser.parse(readerMock, formatMock);
            });
            assertEquals("Test IOException", exception.getMessage());
        }
    }
}
